    pub const fn rune_const_eval(ctx: &Ctx, rune_id: RuneId, attack_type: AttackType) -> f32 {
        match rune_id {
            RuneId::Aftershock => aftershock(ctx),
            RuneId::ArcaneComet => arcane_comet(ctx),
            RuneId::CheapShot => cheap_shot(ctx),
            RuneId::DarkHarvest => dark_harvest(ctx),
            RuneId::Electrocute => electrocute(ctx),
            RuneId::GraspOfTheUndying => match attack_type {
                Melee => grasp_of_the_undying_melee(ctx),
                Ranged => grasp_of_the_undying_ranged(ctx),
            },
            RuneId::Predator => predator(ctx),
            RuneId::PressTheAttack => press_the_attack(ctx),
            RuneId::Scorch => scorch(ctx),
            RuneId::SuddenImpact => sudden_impact(ctx),
            RuneId::SummonAery => summon_aery(ctx),
            _ => 0.0,
        }
    }
